{
  "task_id": "L3-003",
  "task_type": "full_year_rule_audit",
  "question": "请对全年数据做超标准专项扫描,返回全部异常ID和记录ID集合。",
  "audit_period": {
    "start": "2025-01-01",
    "end": "2025-12-31",
    "full_year": true
  },
  "scope": {
    "expense_types": ["travel_lodging", "local_transport", "training_fee", "business_entertainment", "office_supplies", "communication"],
    "departments": "all",
    "employees": "all"
  },
  "policy_questions": [
    {
      "id": "PQ-01",
      "rule": "差旅住宿超标准",
      "policy": "04_travel_expense.md",
      "clause": "第四条",
      "description": "住宿费按员工职级和城市档位确定标准，超过标准且无专项审批的不得报销",
      "thresholds": {
        "E1": {"一类": 450, "二类": 380, "三类": 300},
        "M1": {"一类": 650, "二类": 550, "三类": 450},
        "D1": {"一类": 850, "二类": 700, "三类": 600},
        "X1": {"一类": 1100, "二类": 900, "三类": 750}
      }
    },
    {
      "id": "PQ-02",
      "rule": "市内交通包干超标准",
      "policy": "04_travel_expense.md",
      "clause": "第六条",
      "description": "出差市内交通包干：一类城市120元/日，二类城市100元/日，三类城市80元/日",
      "thresholds": {"一类": 120, "二类": 100, "三类": 80}
    },
    {
      "id": "PQ-03",
      "rule": "培训课程费超标准",
      "policy": "05_training_expense.md",
      "clause": "第二条",
      "description": "培训课程费每人每期不超过3500元",
      "threshold": 3500
    },
    {
      "id": "PQ-04",
      "rule": "内部培训综合费用超标准",
      "policy": "05_training_expense.md",
      "clause": "第三条",
      "description": "内部培训综合费用每日不超过800元",
      "threshold": 800
    },
    {
      "id": "PQ-05",
      "rule": "外部培训综合费用超标准",
      "policy": "05_training_expense.md",
      "clause": "第四条",
      "description": "外部培训综合费用每日不超过1200元",
      "threshold": 1200
    },
    {
      "id": "PQ-06",
      "rule": "培训住宿超标准",
      "policy": "05_training_expense.md",
      "clause": "第五条",
      "description": "培训住宿标准：一类500元，二类420元，三类350元",
      "thresholds": {"一类": 500, "二类": 420, "三类": 350}
    },
    {
      "id": "PQ-07",
      "rule": "业务招待单次超标准",
      "policy": "06_business_entertainment.md",
      "clause": "第二条",
      "description": "业务招待单次活动费用不得超过5000元",
      "threshold": 5000
    },
    {
      "id": "PQ-08",
      "rule": "业务招待人均超标准",
      "policy": "06_business_entertainment.md",
      "clause": "第三条",
      "description": "业务招待费用按参与人数核算，人均不得超过300元",
      "threshold": 300
    },
    {
      "id": "PQ-09",
      "rule": "办公用品月度超标准",
      "policy": "07_office_communication.md",
      "clause": "第二条",
      "description": "员工个人办公用品报销每人每月不超过600元",
      "threshold": 600
    },
    {
      "id": "PQ-10",
      "rule": "通讯费用月度超标准",
      "policy": "07_office_communication.md",
      "clause": "第三条",
      "description": "员工通讯费用报销每人每月不超过300元",
      "threshold": 300
    },
    {
      "id": "PQ-11",
      "rule": "重复报销",
      "policy": "01_expense_reimbursement_2025.md",
      "clause": "第十条",
      "description": "同一发票最多报销1次，重复出现认定为重复报销风险",
      "threshold": null
    },
    {
      "id": "PQ-12",
      "rule": "拆分报销规避审批",
      "policy": "01_expense_reimbursement_2025.md",
      "clause": "第十一条",
      "description": "同一员工、同一费用类型在7天内出现2笔及以上报销，且合计金额达到AR-02线(≥3000元)的，应重点核查",
      "threshold": 3000
    },
    {
      "id": "PQ-13",
      "rule": "超制度标准报销",
      "policy": "01_expense_reimbursement_2025.md",
      "clause": "第十二条",
      "description": "无专项审批时，报销金额不得超过对应制度标准的1.0倍",
      "threshold": null
    },
    {
      "id": "PQ-14",
      "rule": "部门预算超支",
      "policy": "01_expense_reimbursement_2025.md",
      "clause": "第十三条",
      "description": "部门年度预算不足时不得继续报销，预算使用达到1.0倍后需专项审批",
      "threshold": null
    }
  ],
  "data_questions": [
    {
      "id": "DQ-01",
      "description": "获取全年全部4240条费用记录",
      "tables": ["expenses"],
      "fields": ["record_id", "employee_id", "employee_name", "department_id", "expense_date", "expense_type", "amount", "invoice_no", "status", "reason"]
    },
    {
      "id": "DQ-02",
      "description": "获取全部员工信息（职级、部门）",
      "tables": ["employees"],
      "fields": ["employee_id", "employee_level", "department_id", "position_role"]
    },
    {
      "id": "DQ-03",
      "description": "获取各部门年度预算",
      "tables": ["department_budgets"],
      "fields": ["department_id", "budget_amount", "used_amount"]
    },
    {
      "id": "DQ-04",
      "description": "检测重复发票",
      "method": "group by invoice_no, count > 1"
    },
    {
      "id": "DQ-05",
      "description": "检测拆分报销：同一员工、同一类型、7天内≥2笔、合计≥3000",
      "method": "window/group analysis"
    },
    {
      "id": "DQ-06",
      "description": "检测办公用品月度超标：按员工+月份聚合，检查是否>600",
      "method": "group by employee_id, month"
    },
    {
      "id": "DQ-07",
      "description": "检测通讯费月度超标：按员工+月份聚合，检查是否>300",
      "method": "group by employee_id, month"
    },
    {
      "id": "DQ-08",
      "description": "检测差旅住宿超标：按职级+城市档位检查",
      "method": "join employees, compare against thresholds"
    },
    {
      "id": "DQ-09",
      "description": "检测培训费超标：每人每期>3500",
      "method": "filter training_fee, check amount > 3500"
    },
    {
      "id": "DQ-10",
      "description": "检测业务招待费超标：单次>5000，或人均>300",
      "method": "filter business_entertainment"
    },
    {
      "id": "DQ-11",
      "description": "检测部门预算超支",
      "method": "compare cumulative department spend vs budget"
    },
    {
      "id": "DQ-12",
      "description": "检测市内交通超标",
      "method": "compare local_transport against city-tier daily standards"
    }
  ],
  "complexity": {
    "score": 5,
    "reasons": [
      "涉及4个以上制度文件（差旅、培训、招待、办公通讯、报销管理、预算管理）",
      "需要聚合、分组、JOIN分析（按月按人聚合、员工职级JOIN、预算累计）",
      "涉及10条以上业务规则/阈值检查",
      "涉及阈值、日期边界、豁免条件等多维度判断",
      "需要出具综合审计报告"
    ]
  },
  "subagent_plan": {
    "policy_researcher": {
      "required": false,
      "reason": "所有制度均为2025版，无版本冲突或历史制度适用问题，主智能体可直接完成制度解读"
    },
    "data_analyst": {
      "required": true,
      "role": "securities-expense-audit:data-analyst",
      "reason_code": "MULTI_RECORD_SCOPE",
      "context": "对全年4240条费用记录执行超标准专项扫描。需要：1) 分页获取全部记录；2) 按规则逐项检查：差旅住宿按职级+城市档位标准、培训费标准、业务招待费标准、办公用品月度600元上限、通讯费月度300元上限、重复发票、拆分报销(7天内同人同类型≥2笔合计≥3000)、部门预算超支；3) 返回每个异常对应的anomaly_id、record_ids、违规事实。注意：市内交通(local_transport)按差旅政策第六条包干标准检查；培训费中的training_fee类型需要同时检查课程费≤3500和培训住宿标准。",
      "artifact_paths": ["work/audit_plan.json"],
      "requested_token_budget": 150000
    },
    "independent_reviewer": {
      "required": false,
      "reason": "待初步结论和证据矩阵完成后按触发条件决定"
    }
  },
  "execution_steps": [
    {"step": 1, "action": "完成审计规划并记录planning_completed checkpoint", "artifact": "work/audit_plan.json"},
    {"step": 2, "action": "授权并启动数据分板子智能体执行全面数据扫描", "artifact": "work/subagents/data-analyst/"},
    {"step": 3, "action": "主智能体完成制度适用性检查（policy-version-check）", "artifact": "work/policy_applicability.json"},
    {"step": 4, "action": "登记complete_audit_subagent，整合子智能体结论", "artifact": "work/subagent_summary.json"},
    {"step": 5, "action": "形成初步结论，运行evidence-coverage-check", "artifact": "work/evidence_matrix.json"},
    {"step": 6, "action": "根据需要运行false-positive-review", "artifact": "work/independent_review.json"},
    {"step": 7, "action": "运行audit-report生成报告", "artifact": "work/report_draft.json"},
    {"step": 8, "action": "运行result-validator校验", "artifact": "work/validation_report.json"},
    {"step": 9, "action": "调用validate_audit_result和submit_audit_result提交", "artifact": "work/final_result.json"}
  ],
  "stopping_conditions": [
    "所有4240条记录均按适用规则完成检查",
    "evidence_matrix覆盖率达到100%且status为pass",
    "validation_report.json status为pass且submission_allowed为true",
    "validate_audit_result返回valid=true",
    "submit_audit_result成功"
  ],
  "unresolved_items": [
    "市内交通local_transport的包干标准适用于出差场景，需确认数据库中该类型是否均为出差市内交通",
    "业务招待费的人均标准检查需要参与人数信息，数据库中可能无此字段",
    "培训费中内部/外部培训的区分需要从reason字段推断"
  ]
}

